INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-0471a791-moex-00202', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-113-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '民主轉型從發起行為者來看，可以分成「由上而下」或者「由下而上」的兩種方向。由上而下式的民 主轉型（例如墨西哥與臺灣）所帶來的優缺點，下列何者錯誤？', '["寧靜革命，較能避免大規模衝突", "充滿妥協，但也往往無法處理轉型正義的問題", "舊政權下的菁英往往可以透過制定有利的規則來延續政治生命", "族群衝突程度較高，政治手段往往成為迫害政敵的工具"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00203', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-113-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '非歐盟成員國欲申請加入歐盟，最重要的前提要件不包括：', '["必須要使用歐元", "必須具備民主自由的政治體制", "必須承認歐盟法律", "必須是主權獨立的國家"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00204', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-113-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '很多威權國家也都和民主國家一樣具有選舉（例如俄國）。下列何者不是這類選舉的特色？', '["選舉制度存在，但非公平競爭", "執政黨往往會利用各種方式阻礙在野黨的選舉競爭，例如法律手段", "選舉結果的不確定性很高，在野黨往往可以利用選舉來獲得政治權力", "選舉常被獨裁者用來裝飾自己統治的正當性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00205', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-113-c655adf3', 'sub-diplomatic-0471a791-04', NULL, 'single_choice', '最高法院（憲法法院）通常是一個國家在法律上的最高裁決者。關於美國最高法院的敘述，下列何者 錯誤？', '["大法官為終身職，目的是為了讓他們盡量公正、客觀、獨立審判", "目前大法官的意識型態分布為自由派六席，保守派三席", "川普總統任期內（2017-2020年）任命了三位大法官", "大法官的任命案需要經過參議院的審核及同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00206', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-112-13504c0c', 'sub-diplomatic-0471a791-01', NULL, 'essay', '短文寫作：（20分）
王陽明說：「吾輩用功，只求日減，不求日增。」這種減法的原
則，頗能減輕現代繁忙窘迫的生活壓力；但是，老子雖然說「為道日
損」，卻也說「為學日益」，對生活所需的知識和技能，則主張要多
學習和增加。所以，人生什麼項目該用「減法」？什麼項目又該用「加
法」？這是一個需要衡量評估的問題。
請以「人生的減法與加法」為題，列舉至少四個自己需要加減
的項目，並加以闡述。（文長不超過 400 字）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00207', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-112-13504c0c', 'sub-diplomatic-0471a791-01', NULL, 'essay', '作文：（60分）
貝多芬在創作第七號交響曲的諧謔曲，蒐錄了一首古老的奧地
利朝聖詩歌，他以管風琴的某個音作為主線，像織錦般地逐步經營整
首音樂。那個音是 A，整個樂團的樂器都以這個音為準。剛開始時，
這個音聽起來很柔和，然後越來越明顯，最後，銅管聲勢浩大地奏出
一片「顫動的火焰」，這是音樂史上偉大的一刻。
生活的各個領域也是如此，重點是關係整個樂團樂器最初那個
看似不明顯的音。請以貝多芬的創作為借鏡，申述自己生活中「定出
主線，逐步經營」的經驗與見解。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00208', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-112-13504c0c', 'sub-diplomatic-0471a791-01', NULL, 'single_choice', '下列選項前後對話，成語使用最適當的是：', '["「令尊年高八十，猶然老當益壯。」／「家父身手靈活，真是一馬當先。」", "「貴公司業績能逆勢成長，可賀！可賀！」／「這全仰賴大家上下一心。」", "「你家屋內整理得光耀門楣，真是好看。」／「這一切，都是拙荊的心血。」", "「令公子金榜題名，真是蓬蓽生輝！」／「過獎！過獎！小兒不過是班門弄斧。」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00209', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-112-13504c0c', 'sub-diplomatic-0471a791-01', NULL, 'single_choice', '「上個世紀結束後我再次離開美濃。當我在困頓、漂泊的午夜中神遊我莊、回顧自我， 慢慢發現，其實我莊植長在我身體之中，有時甚至就坐在額頭，左右了我人生的轉 彎。而且，它是我理解世界的第一個版本，往後的無數次增修，都將依之據之。」 根據上文，有關作者對「我莊」的敘述，最適當的是：', '["近鄉情怯，離家多年後再次返家，對於「我莊」益發思念", "雖遊歷世界多處，但始終未曾發現比「我莊」更美的地方", "曾在離家後的困頓之際想起「我莊」，進而反思其真正涵義", "時時惦記「我莊」，並藉由遠行經驗多次修改「我莊」形象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00210', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-112-13504c0c', 'sub-diplomatic-0471a791-01', NULL, 'single_choice', '「東方繪畫為主的中國花鳥畫，自古即在其象徵意義上，有更明確的發揮，比如以花 卉為寄寓，作為理想人格的投映。」 下列選項，何者最能呼應上文所述？', '["人面不知何處去，桃花依舊笑春風", "花謝花飛飛滿天，紅消香斷有誰憐", "竹外桃花三兩枝，春江水暖鴨先知", "莫嫌老圃秋容淡，且看黃花晚節香"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL),
  ('diplomatic-0471a791-moex-00211', 'diplomatic-0471a791', 'diplomatic-0471a791-moex-112-13504c0c', 'sub-diplomatic-0471a791-01', NULL, 'single_choice', '行文表述時，合宜地運用正向思維與負向思維，接續排列文句，可達到顛覆與反轉 的趣味。如同曾任英國首相的邱吉爾名言：「你有敵人？很好！那說明在你人生中， 你曾為某些事堅持過。」即是善用了「先負轉正」的敘述方式。 下列那個句子的敘述方式最接近上文例句表述的方式？', '["生命是一襲華美的袍，爬滿了蝨子", "你在黑夜獨行，堅定地走出一路山明水秀", "先要了解事實，然後你才能夠隨心所欲的扭曲誤解它", "這個世界如此美好，值得人們為它奮鬥，我只同意後半句"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:15+00:00", "source_pdf_sha1": "3b9af7388b35", "answer_pdf_sha1": "3a8fb526d509", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-日文組"}'::jsonb, NULL)
